interface MasterIngredient {
  id: number;
  name: string;
  symbol: string;
  keyword: string;
  refrence: string;
  allergen: string;
  manualAllergens?: string[];
  portion: number;
  energy: number;
  protein: number;
  carb: number;
  fat: number;
  totalSugar?: number;
  addedSugar?: number;
  saturatedFat?: number;
  unsaturatedFat?: number;
  polyunsaturatedFat?: number;
  transFat?: number;
  fiber?: number;
  cholesterol?: number;
  sodium?: number;
  createdOn: string;
  status: 'active' | 'inactive';
  brandName?: string;
  rawMaterialId?: string;
  rawMaterialName?: string;
  brandImage?: string;
  evidenceType?: 'link' | 'pdf' | 'image' | '';
  evidenceUrl?: string;
  evidenceName?: string;
  // 'red' marks an ingredient that was added manually because the user couldn't
  // find a match in the database. It signals "data incomplete — please fill in".
  // Cleared automatically when the master ingredient is edited & saved.
  flag?: 'red' | null;
  // True when nutrition values were pre-filled by Gemini because the
  // ingredient wasn't in the master DB or external sources at add time.
  // The UI shows an "AI estimate" chip while this is true. Any explicit
  // user edit (modal save, quick-fill, inline allergen/symbol/name change)
  // flips it back to false so the silent background USDA/FSANZ
  // reconciliation in `addRedFlaggedManualIngredient` won't overwrite the
  // user's accepted values without their consent.
  aiEstimated?: boolean;
  // User-confirmed alternate names that should resolve to this canonical
  // ingredient. Populated when the user accepts a "Use existing X instead?"
  // grouping prompt, or when a duplicate is merged in via the bulk cleanup
  // tool. Stored lowercased & trimmed; future add-ingredient calls match
  // against these alongside the canonical name.
  aliases?: string[];
  // Structured per-ingredient aliases used by the CSV matcher. Each entry
  // can be flagged `exact` (must match the CSV name verbatim after
  // normalization to count as a hit; no fuzzy) and/or `priority` (when
  // matched, this dbItem short-circuits the matcher and beats every
  // other candidate). Curated by the user in the inline aliases editor;
  // legacy `keyword` (comma-string) and `aliases` (string[]) are still
  // honoured by the matcher as plain fuzzy targets for backward compat.
  aliasEntries?: AliasEntry[];
}

interface AliasEntry {
  text: string;
  exact?: boolean;
  priority?: boolean;
}

interface RecipeIngredientRef {
  ingredientId: number;
  quantity: number;
}

interface RecipeItem {
  id: number;
  corporateName: string;
  regionalName: string;
  unitName: string;
  // Free-form location label (e.g. "Main Kitchen, Hyderabad" or "Outlet 12 — Banjara Hills")
  // Persisted in the JSON payload alongside other recipe metadata.
  location?: string;
  name: string;
  symbol: string;
  refrence: string;
  allergen: string;
  manualAllergens?: string[];
  manualDeclarations?: string[];
  // Allergens user listed in the "Specify Allergen Ingredients" section of
  // the uploaded bulk recipe Excel. Surfaced separately in the recipe
  // export's "Allergen Contents (as per Excel)" column.
  excelAllergens?: string[];
  portion: number;
  energy: string;
  protein: string;
  carb: string;
  fat: string;
  totalSugar?: string;
  addedSugar?: string;
  saturatedFat?: string;
  unsaturatedFat?: string;
  polyunsaturatedFat?: string;
  transFat?: string;
  fiber?: string;
  cholesterol?: string;
  sodium?: string;
  createdOn: string;
  isActive: boolean;
  deactivatedOn: string | null;
  servings: number;
  description: string;
  notes: string;
  ingredients: RecipeIngredientRef[];
  isSubRecipe?: boolean;
  // Entity IDs (units/corporates/regions) the super-admin has explicitly
  // shared this recipe with. Stored inside the recipe's JSON payload so the
  // existing save path persists it without a schema migration.
  sharedWith?: string[];
  // When a unit edits a shared recipe, we fork it into a private copy and
  // record the source recipe id here so the unit-side UI can hide the
  // original (which is still served from the API).
  originalRecipeId?: number;
  // Transient: set by the API GET response so the client can tell apart
  // recipes the current user owns vs ones shared with them. Stripped before
  // persistence on both client and server.
  _ownerId?: string;
}

interface CsvAlternativeMatch {
  name: string;
  id: number;
  score: number;
  usageCount: number;
  dbItem: any;
}

interface CsvMatchItem {
  id: string;
  csvName: string;
  csvQty: number;
  matchedTo: string;
  matchedId: number | null;
  matchScore: number;
  matchType: string;
  dbItem: any | null;
  status: 'pending' | 'accepted' | 'rejected' | 'ignored';
  alternatives: CsvAlternativeMatch[];
  locked?: boolean;
  // True for ≥95% (or priority/exact alias) matches. Medium-confidence
  // (85–94%) and low-confidence (<85%) rows start `false` and require
  // explicit one-click user confirmation before "Accept All" will
  // commit them. Set by the matcher on creation and toggled by the
  // per-row Confirm action in Import Review.
  confirmed?: boolean;
  // Snapshot of the matcher's original verdict, captured the first
  // time a user explicitly confirms a row. We then override
  // matchScore→100 / matchType→"Confirmed by user" to reflect the
  // user's verdict in the UI; un-confirming restores these values
  // so the matcher's true confidence remains auditable.
  originalScore?: number;
  originalType?: string;
}

interface CsvUnmatchedItem {
  id: string;
  csvName: string;
  csvQty: number;
}

type ImportResolution = 'new' | 'skip' | 'merge' | 'none';
interface ImportReviewItem {
  parsedItem: MasterIngredient;
  status: 'clean' | 'conflict' | 'error';
  existingMatch?: { id: number; name: string; score: number };
  withinMatch?: { name: string; rowIndex: number; score: number; parsedItem: MasterIngredient };
  reason: string;
  resolution: ImportResolution;
  providedFields: Set<string>;
}

interface RecipeDraft {
  id: string;
  name: string;
  editingRecipeId: number | null;
  title: string;
  description: string;
  servings: string;
  prepTime: string;
  cookTime: string;
  notes: string;
  finalWeight: string;
  ingredients: any[];
  csvMatched: any[];
  csvUnmatched: any[];
  updatedAt: number;
  isSubRecipe?: boolean;
  // Per-draft location label. Pre-populated from the location lock when set.
  location?: string;
  // Allergens the user typed into the "Specify Allergen Ingredients If Any"
  // section of the bulk Excel template. Carried through to the saved
  // RecipeItem so the per-recipe export can show user-supplied vs system-
  // detected allergens side by side.
  excelAllergens?: string[];
  // True when this draft was created by a CSV / Excel bulk import (or the
  // paste-from-spreadsheet flow). Once the user actually saves a recipe,
  // we hide all OTHER bulk-batch drafts from the maker's tabs strip so the
  // editor doesn't keep "opening together" as a wall of leftover tabs on
  // the next visit. The drafts stay in state — a chip lets the user
  // resume them on demand or discard them in one click.
  bulkBatch?: boolean;
}

