  const [unmatchedSortMode, setUnmatchedSortMode] = useState<'best' | 'usage'>(() => {
    if (typeof window === 'undefined') return 'best';
    try {
      const v = window.sessionStorage.getItem('recipeCalc.unmatchedSortMode');
      return v === 'usage' ? 'usage' : 'best';
    } catch { return 'best'; }
  });
  useEffect(() => {
    if (typeof window === 'undefined') return;
    try { window.sessionStorage.setItem('recipeCalc.unmatchedSortMode', unmatchedSortMode); } catch {}
  }, [unmatchedSortMode]);

  // External nutrition lookup (USDA + FSANZ) — opened per CSV review row.
  // Keyed by `${bucket}:${itemId}` so a row in the matched bucket and a row
  // in the unmatched bucket don't collide.
  const [externalLookupOpen, setExternalLookupOpen] = useState<string | null>(null);
  const [externalLookupQuery, setExternalLookupQuery] = useState<Record<string, string>>({});
  // Per-panel local filter — narrows the already-fetched cards across
  // ALL sources (NIN/Japan/Korea/UK/USDA/FSANZ) by name/brand/subSource
  // without firing another network call. Lets the user paste a long
  // result set then pick relevant rows quickly.
  const [externalLookupFilter, setExternalLookupFilter] = useState<Record<string, string>>({});
  const [externalLookupResults, setExternalLookupResults] = useState<Record<string, ExternalSearchResult>>({});
  const [externalLookupLoading, setExternalLookupLoading] = useState<Record<string, boolean>>({});
  const [externalLookupAdopting, setExternalLookupAdopting] = useState<string | null>(null);

  // Standalone "Add ingredient from USDA / FSANZ" modal opened from the
  // Ingredients tab toolbar (no CSV review row context). Reuses the
  // externalLookup* state above (keyed by ADD_FROM_EXTERNAL_KEY) so the
  // search/loading/results plumbing is shared with the CSV-review panel.
  const ADD_FROM_EXTERNAL_KEY = '__add_from_external_modal__';
  const [showAddFromExternal, setShowAddFromExternal] = useState(false);

  // Per-panel sequence counter. Each call to runExternalLookup bumps the
  // counter; partial results are only merged when their captured `seq`
  // still matches the latest seq for that panel. This guarantees a
  // late USDA / FSANZ / internal response from an earlier query (e.g.
  // user typed "to" then "tomato" before the slower source settled)
  // can never overwrite the panel for the newer query.
  const externalLookupSeqRef = useRef<Record<string, number>>({});

  // Local master-ingredient match used as the "internal" source inside
  // the parallel orchestrator. Same simple includes-then-Jaro-ish scoring
  // pattern as the search dropdown elsewhere — kept inline so the
  // orchestrator stays callsite-agnostic and we don't have to thread the
  // master list through the lib layer.
  const buildInternalSearch = useCallback(() => {
    return async (q: string): Promise<ExternalFood[]> => {
      const ql = q.toLowerCase();
      const list = masterIngredientsRef.current || [];
      const scored = list
        .map(m => {
          const name = (m.name || '').toLowerCase();
          if (!name) return null;
          let score = 0;
          if (name === ql) score = 100;
          else if (name.includes(ql)) score = 90;
          else if (ql.split(/\s+/).every(t => t && name.includes(t))) score = 70;
          else return null;
          return { m, score };
        })
        .filter((x): x is { m: MasterIngredient; score: number } => x !== null)
        .sort((a, b) => b.score - a.score)
        .slice(0, 50)
        .map(({ m, score }): ExternalFood => ({
          id: String(m.id),
          source: 'INTERNAL',
          name: m.name,
          portion: m.portion || 100,
          energy: Number(m.energy) || 0,
          protein: Number(m.protein) || 0,
          carb: Number(m.carb) || 0,
          fat: Number(m.fat) || 0,
          fiber: Number(m.fiber) || 0,
          sodium: Number(m.sodium) || 0,
          totalSugar: Number(m.totalSugar) || 0,
          addedSugar: Number(m.addedSugar) || 0,
          saturatedFat: Number(m.saturatedFat) || 0,
          unsaturatedFat: Number(m.unsaturatedFat) || 0,
          polyunsaturatedFat: Number(m.polyunsaturatedFat) || 0,
          transFat: Number(m.transFat) || 0,
          cholesterol: Number(m.cholesterol) || 0,
          allergen: m.allergen || '',
          symbol: (m.symbol === 'NonVeg' ? 'Non-Veg' : 'Veg'),
          matchScore: score,
        }));
      return scored;
    };
  }, []);

  const runExternalLookup = useCallback(async (panelKey: string, query: string) => {
    const q = (query || '').trim();
    if (!q) return;
    // Record into the per-user recent-searches history. Done up-front
    // (before the network call) so the term lands in the dropdown even
    // if the lookup itself errors out — the user still typed it and may
    // want to retry from the dropdown.
    addRecentSearch(userEmail, currentScope, q);
    // Bump the panel's sequence and capture it locally so late partials
    // from a superseded query can be discarded.
    const seq = (externalLookupSeqRef.current[panelKey] || 0) + 1;
    externalLookupSeqRef.current[panelKey] = seq;

    setExternalLookupLoading(prev => ({ ...prev, [panelKey]: true }));
    // Reset prior results immediately so stale data from a previous query
    // doesn't bleed into the new search while sources are still in flight.
    setExternalLookupResults(prev => ({ ...prev, [panelKey]: { fsanz: [], usda: [], nin: [], japan: [], korea: [], uk: [], france: [], china: [], italy: [], openfood: [], aiPredict: [], internal: [] } }));
    try {
      // Streaming merge: every source (Internal + USDA + FSANZ) is fired
      // in parallel and the panel re-renders as soon as any one of them
      // resolves, instead of blocking on the slowest. Per-source errors
      // and timeouts are isolated inside searchExternalStream.
      await searchExternalStream(
        q,
        // perSource bumped from 50 → 80 so the long tail of USDA Branded
        // Foods (FDC's largest dataset, ~1.5M items) doesn't get squeezed
        // out by the few dozen Foundation/SR Legacy hits the route also
        // returns. Open Food Facts also benefits from the wider window.
        { perSource: 80, internalSearch: buildInternalSearch() },
        partial => {
          // Discard partials that belong to a superseded query — keeps
          // the panel consistent under rapid retyping.
          if (externalLookupSeqRef.current[panelKey] !== seq) return;
          setExternalLookupResults(prev => ({
            ...prev,
            [panelKey]: { ...(prev[panelKey] || { fsanz: [], usda: [], nin: [], japan: [], korea: [], uk: [], france: [], china: [], italy: [], openfood: [], aiPredict: [], internal: [] }), ...partial },
          }));
        },
      );
    } catch (e) {
      console.error('External lookup failed:', e);
    } finally {
      // Only the latest run clears the spinner; an older run finishing
      // late shouldn't flip a still-in-flight newer one to "done".
      if (externalLookupSeqRef.current[panelKey] === seq) {
        setExternalLookupLoading(prev => ({ ...prev, [panelKey]: false }));
      }
    }
  }, [buildInternalSearch, userEmail, currentScope]);

  const openExternalLookup = useCallback((panelKey: string, defaultQuery: string) => {
    setExternalLookupOpen(panelKey);
    if (!externalLookupQuery[panelKey]) {
      setExternalLookupQuery(prev => ({ ...prev, [panelKey]: defaultQuery }));
    }
    if (!externalLookupResults[panelKey]) {
      const q = externalLookupQuery[panelKey] || defaultQuery;
      runExternalLookup(panelKey, q);
    }
  }, [externalLookupQuery, externalLookupResults, runExternalLookup]);

  const [ingAllergenDropdownOpen, setIngAllergenDropdownOpen] = useState<number | null>(null);
  const [ingAllergenSearch, setIngAllergenSearch] = useState('');
  const ingAllergenDropdownRef = useRef<HTMLDivElement>(null);
  const [importReviewItems, setImportReviewItems] = useState<ImportReviewItem[]>([]);
  const [showImportReview, setShowImportReview] = useState(false);
