  const [importReviewSelected, setImportReviewSelected] = useState<Set<number>>(new Set());
  const [manualMatchSearch, setManualMatchSearch] = useState<Record<number, string>>({});
  const [manualMatchOpen, setManualMatchOpen] = useState<number | null>(null);
  const [makerAllergenOpenId, setMakerAllergenOpenId] = useState<string | null>(null);
  const [makerAllergenSearch, setMakerAllergenSearch] = useState('');
  const makerAllergenRef = useRef<HTMLDivElement | null>(null);
  // Per-ingredient inline error (keyed by master ingredient id) shown
  // inside the allergen popover when a persist attempt fails. Scoped
  // per-row so a stale failure from row A can't leak into row B.
  const [allergenErrors, setAllergenErrors] = useState<Record<number, string>>({});
  // Per-ingredient AbortController for in-flight allergen saves. Used to
  // cancel an earlier request when the user toggles another chip on the
  // same ingredient before the previous response lands — ensures the
  // server's final state matches the user's last intent.
  const allergenSaveAbortersRef = useRef<Record<number, AbortController>>({});
  // Per-ingredient mutation sequence number. The result of an in-flight
  // request is only applied (revert / clear-error) if it's still the
  // latest mutation for that ingredient — so out-of-order completions
  // cannot clobber newer intent on the client.
  const allergenSaveSeqRef = useRef<Record<number, number>>({});
  // Mirror of `masterIngredients` kept synchronously up-to-date via the
  // effect below. Used by saveMasterAllergen to read the freshest row at
