  // Reading from a ref avoids React's "updater may not run synchronously"
  // pitfall that the in-place setState callback approach has.
  const masterIngredientsRef = useRef<MasterIngredient[]>([]);
  // Per-ingredient inline error (keyed by master ingredient id) shown
  // next to the Veg/NonVeg toggle on a maker row when a persist attempt
  // fails. Same row-scoped pattern as allergenErrors so a stale failure
  // from one row can't surface on another row.
  const [symbolErrors, setSymbolErrors] = useState<Record<number, string>>({});
  // Per-ingredient AbortController + sequence for in-flight symbol saves.
