  // client. Together they guarantee the server's last-write matches the
  // user's last intent even under rapid toggling.
  const symbolSaveAbortersRef = useRef<Record<number, AbortController>>({});
  const symbolSaveSeqRef = useRef<Record<number, number>>({});
  // Inline keyword editor on each maker-row's KW badge. The user opens it by
  // clicking the KW chip, edits the comma-separated keyword list (or hits
