  // localId; keywordDraft holds the in-flight edit text.
  const [keywordEditOpenId, setKeywordEditOpenId] = useState<string | null>(null);
  const [keywordDraft, setKeywordDraft] = useState('');
  const [keywordSaving, setKeywordSaving] = useState(false);
  const [keywordError, setKeywordError] = useState<string | null>(null);
  // New structured aliases editor state. `aliasDraft` is the in-flight
