  const [aliasDraft, setAliasDraft] = useState<AliasEntry[]>([]);
  const [aliasFocusIdx, setAliasFocusIdx] = useState<number | null>(null);
  const keywordEditRef = useRef<HTMLDivElement | null>(null);
  // Inline "Quick fill" panel for red-flagged maker rows. Shows a compact
  // form (energy/protein/carb/fat + allergen) and a "Save & clear flag"
